-- Facebook Page integration. Credentials are stored only as AES-GCM ciphertext.
CREATE TABLE "SocialAccount" ("id" INTEGER NOT NULL PRIMARY KEY AUTOINCREMENT,"shop" TEXT NOT NULL,"platform" TEXT NOT NULL CHECK("platform"='FACEBOOK'),"accountType" TEXT NOT NULL CHECK("accountType"='PAGE'),"externalAccountId" TEXT NOT NULL,"accountName" TEXT NOT NULL,"accountImageUrl" TEXT,"businessId" TEXT,"instagramName" TEXT,"status" TEXT NOT NULL DEFAULT 'NOT_CONNECTED',"permissions" TEXT NOT NULL DEFAULT '[]',"tokenReference" TEXT,"tokenExpiresAt" DATETIME,"lastValidatedAt" DATETIME,"lastSyncedAt" DATETIME,"active" BOOLEAN NOT NULL DEFAULT false,"createdAt" DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP,"updatedAt" DATETIME NOT NULL);
CREATE UNIQUE INDEX "SocialAccount_shop_platform_externalAccountId_key" ON "SocialAccount"("shop","platform","externalAccountId");CREATE INDEX "SocialAccount_shop_platform_active_idx" ON "SocialAccount"("shop","platform","active");
CREATE TABLE "SocialPost" ("id" INTEGER NOT NULL PRIMARY KEY AUTOINCREMENT,"shop" TEXT NOT NULL,"socialAccountId" INTEGER,"platform" TEXT NOT NULL DEFAULT 'FACEBOOK',"postType" TEXT NOT NULL,"title" TEXT,"description" TEXT NOT NULL,"caption" TEXT,"linkUrl" TEXT,"callToAction" TEXT,"status" TEXT NOT NULL DEFAULT 'DRAFT',"createdByAi" BOOLEAN NOT NULL DEFAULT false,"scheduledFor" DATETIME,"approvedAt" DATETIME,"publishedAt" DATETIME,"externalPostId" TEXT,"externalPostUrl" TEXT,"errorMessage" TEXT,"publishFingerprint" TEXT,"createdAt" DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP,"updatedAt" DATETIME NOT NULL,CONSTRAINT "SocialPost_socialAccountId_fkey" FOREIGN KEY("socialAccountId") REFERENCES "SocialAccount"("id") ON DELETE SET NULL ON UPDATE CASCADE);CREATE INDEX "SocialPost_shop_status_scheduledFor_idx" ON "SocialPost"("shop","status","scheduledFor");CREATE INDEX "SocialPost_socialAccountId_idx" ON "SocialPost"("socialAccountId");
CREATE TABLE "SocialMediaAsset" ("id" INTEGER NOT NULL PRIMARY KEY AUTOINCREMENT,"shop" TEXT NOT NULL,"fileName" TEXT NOT NULL,"originalName" TEXT NOT NULL,"title" TEXT,"description" TEXT,"tags" TEXT,"mimeType" TEXT NOT NULL,"fileType" TEXT NOT NULL,"storageUrl" TEXT NOT NULL,"thumbnailUrl" TEXT,"fileSize" INTEGER NOT NULL,"width" INTEGER,"height" INTEGER,"duration" REAL,"status" TEXT NOT NULL DEFAULT 'ACTIVE',"createdAt" DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP,"updatedAt" DATETIME NOT NULL);CREATE INDEX "SocialMediaAsset_shop_status_createdAt_idx" ON "SocialMediaAsset"("shop","status","createdAt");
CREATE TABLE "SocialMediaBlob" ("id" INTEGER NOT NULL PRIMARY KEY AUTOINCREMENT,"assetId" INTEGER NOT NULL,"data" BLOB NOT NULL,"createdAt" DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP,CONSTRAINT "SocialMediaBlob_assetId_fkey" FOREIGN KEY("assetId") REFERENCES "SocialMediaAsset"("id") ON DELETE CASCADE ON UPDATE CASCADE);CREATE UNIQUE INDEX "SocialMediaBlob_assetId_key" ON "SocialMediaBlob"("assetId");
CREATE TABLE "SocialPostAsset" ("id" INTEGER NOT NULL PRIMARY KEY AUTOINCREMENT,"socialPostId" INTEGER NOT NULL,"assetId" INTEGER NOT NULL,"position" INTEGER NOT NULL DEFAULT 0,"createdAt" DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP,CONSTRAINT "SocialPostAsset_socialPostId_fkey" FOREIGN KEY("socialPostId") REFERENCES "SocialPost"("id") ON DELETE CASCADE ON UPDATE CASCADE,CONSTRAINT "SocialPostAsset_assetId_fkey" FOREIGN KEY("assetId") REFERENCES "SocialMediaAsset"("id") ON DELETE RESTRICT ON UPDATE CASCADE);CREATE UNIQUE INDEX "SocialPostAsset_socialPostId_assetId_key" ON "SocialPostAsset"("socialPostId","assetId");CREATE INDEX "SocialPostAsset_assetId_idx" ON "SocialPostAsset"("assetId");
CREATE TABLE "SocialApproval" ("id" INTEGER NOT NULL PRIMARY KEY AUTOINCREMENT,"shop" TEXT NOT NULL,"socialPostId" INTEGER NOT NULL,"status" TEXT NOT NULL DEFAULT 'PENDING',"approvedBy" TEXT,"approvedAt" DATETIME,"rejectedAt" DATETIME,"rejectionReason" TEXT,"createdAt" DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP,"updatedAt" DATETIME NOT NULL,CONSTRAINT "SocialApproval_socialPostId_fkey" FOREIGN KEY("socialPostId") REFERENCES "SocialPost"("id") ON DELETE CASCADE ON UPDATE CASCADE);CREATE UNIQUE INDEX "SocialApproval_shop_socialPostId_key" ON "SocialApproval"("shop","socialPostId");CREATE INDEX "SocialApproval_shop_status_idx" ON "SocialApproval"("shop","status");
CREATE TABLE "SocialPublishLog" ("id" INTEGER NOT NULL PRIMARY KEY AUTOINCREMENT,"shop" TEXT NOT NULL,"socialPostId" INTEGER NOT NULL,"socialAccountId" INTEGER,"action" TEXT NOT NULL,"requestType" TEXT NOT NULL,"success" BOOLEAN NOT NULL,"externalPostId" TEXT,"errorCode" TEXT,"errorMessage" TEXT,"createdAt" DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP,CONSTRAINT "SocialPublishLog_socialPostId_fkey" FOREIGN KEY("socialPostId") REFERENCES "SocialPost"("id") ON DELETE CASCADE ON UPDATE CASCADE,CONSTRAINT "SocialPublishLog_socialAccountId_fkey" FOREIGN KEY("socialAccountId") REFERENCES "SocialAccount"("id") ON DELETE SET NULL ON UPDATE CASCADE);CREATE INDEX "SocialPublishLog_shop_createdAt_idx" ON "SocialPublishLog"("shop","createdAt");CREATE INDEX "SocialPublishLog_socialPostId_idx" ON "SocialPublishLog"("socialPostId");
CREATE TABLE "EncryptedCredential" ("id" INTEGER NOT NULL PRIMARY KEY AUTOINCREMENT,"shop" TEXT NOT NULL,"reference" TEXT NOT NULL,"provider" TEXT NOT NULL,"ciphertext" TEXT NOT NULL,"iv" TEXT NOT NULL,"authTag" TEXT NOT NULL,"createdAt" DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP,"updatedAt" DATETIME NOT NULL);CREATE UNIQUE INDEX "EncryptedCredential_reference_key" ON "EncryptedCredential"("reference");CREATE INDEX "EncryptedCredential_shop_provider_idx" ON "EncryptedCredential"("shop","provider");
CREATE TABLE "MetaOAuthState" ("id" INTEGER NOT NULL PRIMARY KEY AUTOINCREMENT,"shop" TEXT NOT NULL,"state" TEXT NOT NULL,"encryptedPayload" TEXT,"payloadIv" TEXT,"payloadAuthTag" TEXT,"expiresAt" DATETIME NOT NULL,"consumedAt" DATETIME,"createdAt" DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP);CREATE UNIQUE INDEX "MetaOAuthState_state_key" ON "MetaOAuthState"("state");CREATE INDEX "MetaOAuthState_shop_expiresAt_idx" ON "MetaOAuthState"("shop","expiresAt");
CREATE TABLE "SocialSettings" ("id" INTEGER NOT NULL PRIMARY KEY AUTOINCREMENT,"shop" TEXT NOT NULL,"testMode" BOOLEAN NOT NULL DEFAULT true,"autopilotEnabled" BOOLEAN NOT NULL DEFAULT false,"maxPostsPerDay" INTEGER NOT NULL DEFAULT 1,"emergencyStop" BOOLEAN NOT NULL DEFAULT true,"confirmedPageId" TEXT,"createdAt" DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP,"updatedAt" DATETIME NOT NULL);CREATE UNIQUE INDEX "SocialSettings_shop_key" ON "SocialSettings"("shop");
